const input = $input.first().json;
const body = input.body || input;
const products = body.products || [];
const marketplace = body.marketplace || 'unknown';
const vendorId = body.vendorId || 'unknown';

if (products.length > 500) {
  return [{ json: { success: 0, errors: 1, total: 0, products: [], errorList: [{ sku: 'N/A', message: 'Maximo 500 productos' }], marketplace, vendorId } }];
}
if (products.length === 0) {
  return [{ json: { success: 0, errors: 0, total: 0, products: [], errorList: [], marketplace, vendorId } }];
}

const IMGPROXY_BASE = 'https://image-tools-imgproxy.reyl9a.easypanel.host/insecure/rs:fit:1000:1500/bg:ffffff/extend:1:ce/format:jpg/quality:90';
const includeBase64 = products.length <= 20;
const results = [];
const errorList = [];
let successCount = 0;
let errorCount = 0;

for (const product of products) {
  const { sku, imageUrl } = product;
  if (!sku || !imageUrl) {
    errorCount++;
    errorList.push({ sku: sku || 'unknown', message: 'Falta sku o imageUrl' });
    results.push({ sku: sku || 'unknown', originalUrl: imageUrl || '', convertedUrl: '', status: 'error', imageBase64: null });
    continue;
  }
  try {
    const encodedUrl = Buffer.from(imageUrl).toString('base64url');
    const imgproxyUrl = IMGPROXY_BASE + '/' + encodedUrl;
    const response = await this.helpers.httpRequest({
      method: 'GET',
      url: imgproxyUrl,
      encoding: 'arraybuffer',
      returnFullResponse: true,
      timeout: 15000
    });
    const imageBuffer = Buffer.from(response.body);
    const imageBase64 = includeBase64 ? imageBuffer.toString('base64') : null;
    const cdnUrl = 'https://cdn.prometeix.com/' + marketplace + '/' + vendorId + '/' + sku + '.jpg';
    successCount++;
    results.push({ sku, originalUrl: imageUrl, convertedUrl: cdnUrl, status: 'ok', imageBase64 });
  } catch (err) {
    errorCount++;
    errorList.push({ sku, message: err.message || 'Error desconocido' });
    results.push({ sku, originalUrl: imageUrl, convertedUrl: '', status: 'error', imageBase64: null });
  }
}

return [{ json: { success: successCount, errors: errorCount, total: products.length, products: results, errorList, marketplace, vendorId, includeBase64 } }];

const data = $input.first().json;
const response = {
  success: data.success,
  errors: data.errors,
  total: data.total,
  marketplace: data.marketplace,
  vendorId: data.vendorId,
  products: data.products.map(p => {
    const item = { sku: p.sku, originalUrl: p.originalUrl, convertedUrl: p.convertedUrl, status: p.status };
    if (data.includeBase64 && p.imageBase64) item.imageBase64 = p.imageBase64;
    return item;
  }),
  errorList: data.errorList,
  processedAt: new Date().toISOString()
};
return [{ json: response }];

